document.addEventListener("DOMContentLoaded", () => {
  const containers = document.querySelectorAll("[data-tab-container]");
  containers.forEach((container) => {
    const links = container.querySelectorAll("[data-tab-target]");
    links.forEach((link) => {
      link.addEventListener("click", (event) => {
        event.preventDefault();
        const targetSelector = link.getAttribute("data-tab-target");
        const targetPane = container.querySelector(targetSelector);
        if (!targetPane) {
          return;
        }
        links.forEach((item) => item.classList.remove("active"));
        container.querySelectorAll(".tab-pane").forEach((pane) => {
          pane.classList.remove("active");
        });
        link.classList.add("active");
        targetPane.classList.add("active");
        if (window.Plotly) {
          targetPane.querySelectorAll(".js-plotly-plot").forEach((plot) => {
            try {
              window.Plotly.Plots.resize(plot);
            } catch (err) {
              /* no-op */
            }
          });
        }
      });
    });
  });
});
